const cellKey = (x: number, y: number): string => `${x},${y}`;

const survivesOrIsBorn = (neighborCount: number, isAlive: boolean): boolean =>
  neighborCount === 3 || (neighborCount === 2 && isAlive);

export function nextGeneration(liveCells: Array<Cell>): Array<Cell> {
  const liveSet = new Set<string>(liveCells.map(([x, y]) => cellKey(x, y)));
  const neighborTallies = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      const k = cellKey(nx, ny);
      const existing = neighborTallies.get(k);
      if (existing) existing.count++;
      else neighborTallies.set(k, { cell: [nx, ny], count: 1 });
    }
  }

  const result: Array<Cell> = [];
  for (const [k, { cell, count }] of neighborTallies) {
    if (survivesOrIsBorn(count, liveSet.has(k))) result.push(cell);
  }
  return result;
}

